import React from 'react';
import { heartSpinnerStyles as styles } from './Styles/HeartSpinnerStyle';
import Mappings from '../Helpers/Mappings';

const HeartSpinner: React.FC = () => {
  return (
    <div style={styles.container}>
      <style>
        {`
          @keyframes fillHeart {
            0% { width: 0; height: 0; opacity: 0; }
            50% { width: 60px; height: 60px; opacity: 1; }
            100% { width: 80px; height: 80px; opacity: 1; }
          }
        `}
      </style>
      <div style={styles.heart}>
        <div style={styles.fill}></div>
      </div>
      <p style={styles.text}>{Mappings.heartSpinnerText}</p>
    </div>
  );
};

export default HeartSpinner;