import React from "react";
import { CountdownHelper } from "../Helpers/CountdownHelper";
import { ICountdownInterface, ICountdownProps } from "./Interfaces/ICountdownInterface";

const CountdownComponent: React.FC<ICountdownInterface> = ({ targetDate, onComplete }) => {
  const m : ICountdownProps = CountdownHelper({targetDate, onComplete});

  return (
    <div style={{ textAlign: "center", padding: 18, color: "#2c0335" }}>
      <h2>Countdown fino al momento speciale</h2>
      {m.total > 0 ? (
        <div style={{ fontSize: "2rem", fontWeight: "bold", color: "#b71a49" }}>
          {String(m.days).padStart(2, "0")}d : {String(m.hours).padStart(2, "0")}h : {String(m.minutes).padStart(2, "0")}m : {String(m.seconds).padStart(2, "0")}s
        </div>
      ) : (
        <div style={{ fontSize: "1.6rem", color: "#0f8a5f" }}>
          È il momento! 🎉<br />La sorpresa è pronta.
        </div>
      )}
      <p style={{ marginTop: 10, fontSize: "1.1rem", color: "#6f2e55", fontStyle: "italic" }}>
        {m.message}
      </p>
    </div>
  );
};

export default CountdownComponent;