import dayjs from "dayjs";
import timezone from "dayjs/plugin/timezone";
import utc from "dayjs/plugin/utc";
import { useEffect, useState, useMemo } from "react";
import { ICountdownInterface, ICountdownProps } from "../Component/Interfaces/ICountdownInterface";
import { calculateRemaining } from "./CalculatorHelper";
import Mappings from "./Mappings";

dayjs.extend(utc);
dayjs.extend(timezone);


export const CountdownHelper = ({
  targetDate,
  onComplete,
  messagesByHour,
} : ICountdownInterface): ICountdownProps => {
  
   const messages = useMemo(() => messagesByHour || Mappings.countdownMessages, [messagesByHour]);
   const [countdown, setCountdown] = useState<ICountdownProps>(calculateRemaining(targetDate, messages, onComplete));
 
  useEffect(() => {
    const tick = () => setCountdown(calculateRemaining(targetDate, messages, onComplete));
    tick();
    const timer = setInterval(tick, 1000);
    return () => clearInterval(timer);
  }, [targetDate, messages, onComplete]);

  return countdown;
};