import dayjs from "dayjs";
import utc from "dayjs/plugin/utc";
import timezone from "dayjs/plugin/timezone";
import { ICountdownMessageInterface } from "../Component/Interfaces/ICountdownInterface";

dayjs.extend(utc);
dayjs.extend(timezone);

export const calculateRemaining = (
  targetDate: string,
  messages: ICountdownMessageInterface[],
  onComplete?: () => void
) => {
  const now = dayjs().tz("Europe/Rome");
  const target = dayjs.tz(targetDate, "Europe/Rome"); 

  const diff = target.diff(now);
  const total = diff > 0 ? diff : 0;
  const secondsTotal = Math.floor(total / 1000);

  const remaining = {
    total,
    days: Math.floor(secondsTotal / 86400),
    hours: Math.floor((secondsTotal % 86400) / 3600),
    minutes: Math.floor((secondsTotal % 3600) / 60),
    seconds: secondsTotal % 60,
  };

  let message = "Il conto alla rovescia continua… presto qualcosa di speciale ti aspetta 💌";
  if (remaining.total <= 0) {
    message = "Buon compleanno! Il momento più romantico è arrivato. Apri la lettera d'amore. ❤️";
    onComplete?.();
  } else {
    const currentHour = now.hour();
    const msgObj = messages.find((m) => currentHour >= m.start && currentHour <= m.end);
    if (msgObj) {
      const texts = msgObj.texts;
      message = texts[Math.floor(Math.random() * texts.length)];
    }
  }

  return { ...remaining, message };
};